export const priorityPhilosopherMisunderstandings:Record<string,string[]>={
  plato:['The Forms are not merely physical objects in another location; they answer a problem about intelligibility and standards.','A speech by Socrates or another dialogue character is not automatically Plato’s final doctrine.'],
  aristotle:['The “golden mean” is not a rule to choose the mathematical middle in every case.','Final causes do not mean every natural process consciously pursues a goal.'],
  augustine:['The Confessions is not only autobiography; its narrative is part of an argument about desire, memory, creation, and time.','Evil as privation does not mean suffering is unreal or morally unimportant.'],
  aquinas:['The Five Ways are not intended as five self-contained modern scientific proofs.','Aquinas does not treat faith as a substitute for reasoning; he carefully distinguishes their domains.'],
  descartes:['The cogito is not simply the premise “I think” inserted into a syllogism.','Descartes’ treatment of embodiment and emotion is more developed than the phrase “ghost in the machine” suggests.'],
  hume:['Humean skepticism does not require abandoning ordinary life or scientific inquiry.','His claim that reason does not motivate by itself is not a claim that reasoning never matters in action.'],
  kant:['The categorical imperative is not merely “follow rules regardless of consequences.”','Transcendental idealism does not straightforwardly claim that the external world is an illusion.'],
  nietzsche:['“Will to power” is not a simple command to dominate other people.','Perspectivism does not mean every opinion is equally good or that truth is irrelevant.'],
  wittgenstein:['“Meaning is use” is a methodological reminder, not a complete one-line theory of every kind of meaning.','The later philosophy does not simply ban difficult questions; it asks how language gives them their apparent force.'],
  heidegger:['Authenticity is not lifestyle individualism or freedom from all social relations.','The critique of technology is not a demand to reject devices and return to a premodern life.'],
  beauvoir:['“One is not born, but rather becomes, a woman” does not deny embodiment; it analyzes how embodiment acquires social meaning.','Beauvoir is not merely a commentator applying Sartre’s philosophy.'],
  foucault:['Foucault does not claim that power is possessed only by a ruling group or that resistance is impossible.','Calling a category historically produced does not mean its effects are unreal.']
};
